'use strict';

const { Visitable } = require(
    '../../fromJsonSchema/cto/jsonSchemaClasses.js'
);

/**
 * An OpenApiDefinition visitable class.
 *
 * @class
 */
class OpenApiDefinition extends Visitable {
    /**
     * @param {Object} body - the body.
     *
     */
    constructor(body) {
        super(body, []);
    }

    isOpenApiDefinition = true;
}

module.exports = {
    OpenApiDefinition,
};
