'use strict';

/**
 * Throws an error for an unrecognized type
 * @param {*} thing the unrecognized value
 */
function throwUnrecognizedType(thing) {
    throw new Error(`Unrecognised type: ${typeof thing}, value: '${thing}'`);
}

module.exports = {
    throwUnrecognizedType,
};